func (c *Curve) PrivateKey(rand io.Reader, bits int) (PrivKey, error) {
	var privkey PrivKey
	switch c.Type {
	case ed25519:
		privkey = make([]byte, 32)
		if _, err := io.ReadFull(rand, privkey); err != nil {
			return nil, err
		}
	case ecdsa:
		if bits == 0 {
			bits = 256
		}
		numBytes := (bits + 7) / 8
		privkey = make([]byte, numBytes)
		if _, err := io.ReadFull(rand, privkey); err != nil {
			return nil, err
		}
	case goeth:
		privkey = make([]byte, 32)
		if _, err := rand.Read(privkey); err != nil {
			return nil, err
		}
	case secp256k1:
		privkey = make([]byte, 32)
		if _, err := io.ReadFull(rand, privkey); err != nil {
			return nil, err
		}
	case sonic:
		privkey = make([]byte, 32)
		if _, err := io.ReadFull(rand, privkey); err != nil {
			return nil, err
		}
	}
	return privkey, nil
}

