def load_yaml(filename, required=True, fail_okay=False):
    """Load a YAML file."""
    if required and not os.path.isfile(filename):
        raise Exception("No such file: %s" % filename)
    try:
        with open(filename, 'r') as stream:
            return yaml.safe_load(stream)
    except yaml.YAMLError as exc:
        if hasattr(exc, 'problem_mark'):
            mark = exc.problem_mark
            raise Exception("Error in config file %s at line %s, col %s: %s" %
                            (filename, mark.line + 1, mark.column + 1,
                             exc))
        raise Exception("Error in config file %s: %s" % (filename, exc))
    except IOError as exc:
        if fail_okay:
            return None
        raise Exception("I/O error({0}): {1}".format(exc.errno, exc.strerror))

