def _migrate_map(contents):
    # Find the first non-header line
    lines = contents.splitlines(True)
    i = 0
    while i < len(lines) and lines[i].startswith('#'):
        i += 1

    # If there is no repos section, add one
    if i < len(lines) and lines[i].startswith('repos:'):
        return contents
    else:
        return contents[:i] + '\nrepos:\n' + contents[i:]

