def update_device(self, device_id, data):
        """Update a device's details

        :param device_id: id of the device to update
        :type device_id: int
        :param data: the fields to update and their values
        :type data: dict
        :return: the updated device
        :rtype: dict
        """

        required = ['name', 'mac', 'ip', 'os', 'site_id', 'rack_id', 'position']
        for field in required:
            if field not in data:
                raise Device42APIError('Missing required field: {0}'.format(field))

        for field in data:
            if field not in self.valid_device_fields:
                raise Device42APIError('Unknown field: {0}'.format(field))

        url = 'api/2.0/device/{0}'.format(device_id)
        response = self.session.put(url, json=data)
        return response.json()

