            if t[6:] not in self.version_map:
                errors.append("Unknown version tag '%s' for feature %s." %
                              (t, feature))
        elif t.startswith("bugzilla:"):
            if t[7:] not in self.bugzilla_component_map:
                errors.append("Unknown bugzilla tag '%s' for feature %s." %
                              (t, feature))
        elif t not in self.tag_registry:
            errors.append("Unknown tag '%s' for feature %s." % (t, feature))
    return errors

