    const std::string& tile_file,
    const std::string& tiling_file1,
    const std::string& tiling_file2,
    const std::string& output_file)
{
    // Read tiling information
    LOG(4) << "Reading tiling information from " << tiling_file1;
    H5::H5File file1(tiling_file1, H5F_ACC_RDONLY);
    H5::Group root1 = file1.openGroup("/");
    H5::Group tile_group1 = root1.openGroup("Tile");
    tiling_info_t tiling_info1;
    read_tiling_info(tile_group1, tiling_info1);

    LOG(4) << "Reading tiling information from " << tiling_file2;
    H5::H5File file2(tiling_file2, H5F_ACC_RDONLY);
    H5::Group root2 = file2.openGroup("/");
    H5::Group tile_group2 = root2.openGroup("Tile");
    tiling_info_t tiling_info2;
    read_tiling_info(tile_group2, tiling_info2);

    // Check if the two tilings are compatible
    if (tiling_info1.dataset_ndim != tiling_info2.dataset_ndim) {
        std::string err = "The dimensions of the two tilings must be the same.";
        throw H5::FileIException(err);
    }
    for (unsigned int i = 0; i < tiling_info1.dataset_ndim; i++) {
        if (tiling_info1.tile_size[i] != tiling_info2.tile_size[i]) {
            std::string err = "The tile size of the two tilings must be the same.";
            throw H5::FileIException(err);
        }
    }

    // Open the tile file and the dataspace within
    H5::H5File tfile(tile_file, H5F_ACC_RDONLY);
    H5::Dataspace filespace = tfile.openDataspace("/");

    // Get the dimension sizes of the tile file
    hsize_t *dims = filespace.getSimpleExtentDims();
    hsize_t tile_size = 1;
    for (unsigned int i = 0; i < tiling_info1.dataset_ndim; i++) {
        tile_size *= dims[i];
        dims[i] /= tiling_info1.tile_size[i];
    }
    LOG(4) << "Generated " << dims[0] << "x" << dims[1] << " tile file";

    // Create an output file
    H5::H5File ofile(output_file, H5F_ACC_TRUNC);

    // Walk through the tiles in the file and write them to the new file
    hsize_t offset[2];
    hsize_t count[2];
    hsize_t chunk[2];
    for (offset[0] = 0; offset[0] < dims[0]; offset[0]++) {
        offset[1] = 0;
        for (count[0] = 0; count[0] < tiling_info1.tile_size[0]; count[0]++) {
            offset[1] = 0;
            for (count[1] = 0; count[1] < tiling_info1.tile_size[1]; count[1]++) {
                chunk[0] = offset[0];
                chunk[1] = offset[1];
                H5::Dataspace mspace(H5S_SIMPLE);
                H5::ArrayInputStream mstream(mspace, filespace, chunk, count);
                write_tile_data_tiling2(ofile, mstream, tiling_info2, offset);
                offset[1] += tiling_info2.tile_size[1];
            }
            offset[0] += tiling_info2.tile_size[0];
        }
    }

    // Close
    free(dims);
}

