def update_shared_config(shared_config, yaml_files):
  for yaml_file in yaml_files:
    with open(yaml_file, 'r') as f:
      data = yaml.safe_load(f)
      for k, v in data.items():
        if k not in shared_config:
          shared_config[k] = v
        else:
          if isinstance(shared_config[k], list) and isinstance(v, list):
            shared_config[k].extend(v)
          elif shared_config[k] == v:
