static void *load_data_from_yaml(const char *yamlfile, size_t *length)
{
    void *data = NULL;

    if (access(yamlfile, F_OK) != 0)
        return NULL;

    FILE *fd = fopen(yamlfile, "r");
    if (fd == NULL)
        return NULL;

    fseek(fd, 0, SEEK_END);
    *length = ftell(fd);
    fseek(fd, 0, SEEK_SET);
    data = malloc(*length + 1);
    if (data == NULL) {
        fclose(fd);
        return NULL;
    }
    if (fread(data, *length, 1, fd) != 1) {
        fclose(fd);
        free(data);
        return NULL;
    }
    ((char *)data)[*length] = '\0';
    fclose(fd);

    return data;
}

