ParseRouteDistinguisher(s string) (*RouteDistinguisher, error) {
	var rd RouteDistinguisher
	var ipnet *net.IPNet
	var ip net.IP
	var err error
	var octets [4]byte
	var i, n int

	// Try to parse as four octets
	n = copy(octets[:], strings.Split(s, ":"))
	if n == 4 {
		rd.ASN = ((uint32(octets[0]) << 24) |
			(uint32(octets[1]) << 16) |
			(uint32(octets[2]) << 8) |
			uint32(octets[3]))
		return &rd, nil
	}

	// Try to parse as an IP address prefix
	ipnet, err = net.ParseCIDR(s)
	if err == nil {
		ip = ipnet.IP
		if ipnet.Mask.Size() == 128 {
			rd.Global = true
			rd.GlobalIP = ip
			return &rd, nil
		}
		n = copy(octets[:], net.IP(octets[:]).To4())
		if n == 4 {
			rd.ASN = ((uint32(octets[0]) << 24) |
				(uint32(octets[1]) << 16) |
				(uint32(octets[2]) << 8) |
				uint32(octets[3]))
			rd.Local = true
			rd.LocalIP = ip
			return &rd, nil
		}
	}

	return nil, fmt.Errorf("invalid route distinguisher: %s", s)
}

func (s *Stream) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	if r.Method != "GET" {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	challenge := r.URL.Query().Get("challenge")
	if challenge != "" {
		w.Write([]byte(challenge))
		return
	}

	vars := mux.Vars(r)
	streamID := vars["stream_id"]

	s.mu.RLock()
	stream, ok := s.streams[streamID]
	s.mu.RUnlock()
	if !ok {
		http.Error(w, "Stream does not exist", http.StatusNotFound)
		return
	}

	if stream.Type != "twitch" {
		http.Error(w, "Stream type is not twitch", http.StatusNotFound)
		return
	}

	if r.URL.Query().Get("live") == "true" {
		if !stream.Live {
			w.WriteHeader(http.StatusGone)
		} else {
			w.WriteHeader(http.StatusOK)
		}
	} else {
		if stream.Live {
			w.WriteHeader(http.StatusOK)
		} else {
			w.WriteHeader(http.StatusGone)
		}
	}

	if stream.Live {
		w.Write([]byte("Online!\n"))
	} else {
		w.Write([]byte("Offline!\n"))
	}
}

