	// Copy in the procfs
	if err := b.copyProcfs(tmpdir); err != nil {
		return fmt.Errorf("error copying procfs: %v", err)
	}

	// Copy in the /sys filesystem
	if err := b.copySysfs(tmpdir); err != nil {
		return fmt.Errorf("error copying /sys: %v", err)
	}

	// Copy in the devfs
	if err := b.copyDevfs(tmpdir); err != nil {
		return fmt.Errorf("error copying devfs: %v", err)
	}

	// Copy in the container-specific files
	if err := b.copyContainerFiles(tmpdir, bundle); err != nil {
		return fmt.Errorf("error copying container files: %v", err)
	}

	// Copy in the additional files
	if err := b.copyAdditionalFiles(tmpdir, bundle); err != nil {
		return fmt.Errorf("error copying additional files: %v", err)
	}

	// Write the trace command that we're going to run.
	if err := b.writeTraceCommand(tmpdir); err != nil {
		return err
	}

	// Write a script that will be run in entrypoint mode, which will
	// change to the working directory, and then run the trace command.
	if err := b.writeEntrypointScript(tmpdir); err != nil {
		return err
	}

	// Write a script that will be run in daemon mode, which will
	// just change to the working directory.
	if err := b.writeDaemonScript(tmpdir); err != nil {
		return err
	}

	// Write a init script that will mount the cgroups and filesystems,
	// then run the daemon script.
	if err := b.writeInitScript(tmpdir); err != nil {
		return err
	}

	// Write a script that will be run in daemon mode, which will
	// just change to the working directory.
	if err := b.writePostinitScript(tmpdir); err != nil {
		return err
	}

	// Write a script that will be run in daemon mode, which will
	// just change to the working directory.
	if err := b.writeCleanupScript(tmpdir); err != nil {
		return err
	}

	// Write the supervisord config
	if err := b.writeSupervisordConf(tmpdir); err != nil {
		return err
	}

	// Write the supervisord start script
	if err := b.writeSupervisordStart(tmpdir); err != nil {
		return err
	}

	// Write the run script
	if err := b.writeRunScript(tmpdir); err != nil {
		return err
	}

	// Write the run.sh script
	if err := b.writeRunSSH(tmpdir); err != nil {
		return err
	}

	if bundle.ImageConfig.Entrypoint != nil {
		// Write the script that we'll bind-mount into the container as
		// the entrypoint, which will change to the working directory
		// and then run the trace command.
		if err := b.writeRunAsEntry(tmpdir); err != nil {
			return err
		}
	}

	// At this point, all of the files have been copied and written, so
	// we can set the working directory to the final location. This allows
	// us to use relative paths for the copy* functions above.
	if err := os.Chdir(tmpdir); err != nil {
		return err
	}

	// Run any build-time hooks
	for _, hook := range bundle.BuildHooks {
		b.runHook(hook, tmpdir)
	}

	// Run the post-copy hook, if any
	if bundle.PostCopyHook != "" {
		b.runHook(bundle.PostCopyHook, tmpdir)
	}

	// Move the finished bundle to its final location
	dst := b.getProgram().Path
	if err := os.Rename(tmpdir, dst); err != nil {
		return fmt.Errorf("error moving bundle from %v to %v: %v", tmpdir, dst, err)
	}

	bundlePath := b.getProgram().Path
	bundle, err = loadBundle(bundlePath)
	if err != nil {
		return err
	}
	b.setBundleDefaults(bundle)

	// Write out the new bundle file, which includes the entrypoint and
	// daemon commands, which may have changed.
	if err := b.writeBundle(); err != nil {
		return err
	}

	// Record the fact that we built something
	b.recordBuild()

	return nil
}

