	name := mname(r)
	if name == "" {
		http.Error(w, "no basket name given", http.StatusBadRequest)
		return
	}

	// Validate method
	switch r.Method {
	case http.MethodPost:
		s.handleHTTPBasketPost(w, r, ctx, name)
	case http.MethodGet:
		s.handleHTTPBasketGet(w, r, ctx, name)
	case http.MethodPut:
		s.handleHTTPBasketPut(w, r, ctx, name)
	case http.MethodDelete:
		s.handleHTTPBasketDelete(w, r, ctx, name)
	default:
		http.Error(w, "unsupported method", http.StatusMethodNotAllowed)
	}
}

