public void doWork() throws Exception {
    try {
        super.doWork();
    } catch (Exception e) {
        ExceptionUtils.handleThrowable(e);
        pageContext.setAttribute("javax.servlet.error.exception", e, PageContext.REQUEST_SCOPE);
        Throwable throwable = e;
        // walk the throwable chain and find the root cause
        while (throwable.getCause() != null) {
            throwable = throwable.getCause();
        }
        pageContext.setAttribute("javax.servlet.error.rootCause", throwable, PageContext.REQUEST_SCOPE);
        Integer statusCode = (Integer) pageContext.getAttribute("javax.servlet.error.status_code", PageContext.REQUEST_SCOPE);
        if (statusCode == null) {
            if (throwable instanceof ServletException) {
                ServletException se = (ServletException) throwable;
                statusCode = se.getServletError();
            }
            if (statusCode == null) {
                statusCode = 500;
            }
        }
        RequestDispatcher dispatcher = pageContext.getRequest().getRequestDispatcher("/error/" + statusCode);
        if (dispatcher == null) {
            dispatcher = pageContext.getRequest().getRequestDispatcher("/error");
        }
        dispatcher.forward(pageContext.getRequest(), pageContext.getResponse());
    }
}

