function page_init() {
    // add quality control buttons
    if (page.qualityControl) {
        var qcButton = document.createElement("button");
        qcButton.className = "btn btn-primary";
        qcButton.appendChild(document.createTextNode("Mark as " + page.qualityControl + " quality"));
        qcButton.addEventListener("click", function() {
            document.location = "/page/" + page.id + "/quality/" + page.qualityControl;
        });
        document.getElementById("page-header").appendChild(qcButton);
    }

    // add a button to show the image in a new window
    var viewButton = document.createElement("button");
    viewButton.className = "btn btn-default";
    viewButton.appendChild(document.createTextNode("View full size"));
    viewButton.addEventListener("click", function() {
        window.open("/image/" + page.image.id, "_blank");
    });
    document.getElementById("page-header").appendChild(viewButton);

    // add a link to the previous page
    if (page.previous) {
        var previousLink = document.createElement("a");
        previousLink.href = "/page/" + page.previous.id;
        previousLink.appendChild(document.createTextNode("Previous page"));
        document.getElementById("page-header").appendChild(previousLink);
    }

    // add a link to the next page
    if (page.next) {
        var nextLink = document.createElement("a");
        nextLink.href = "/page/" + page.next.id;
        nextLink.appendChild(document.createTextNode("Next page"));
        document.getElementById("page-header").appendChild(nextLink);
    }

    document.title = page.image.title + " - Page " + page.pageNumber;
}

