searchAll(e) {
    e.preventDefault();
    let query = $("#searchInput").val().trim();
    if (!query) {
        window.location = url_root + "/search";
        return;
    }
    $("#searchInput").val(query);
    window.history.pushState({}, "", url_root + "/search/" + query);
    search(query, "members", "searchMembers");
    search(query, "entities", "searchEntities");
}search(query, type, target) {
    let url = url_root + "/search/" + type + ".json?" + $("#searchForm").serialize();
    $.getJSON(url, function(data) {
        let html = Mustache.render($("#search-results-template").html(), {
            results: data,
            type: type
        });
        $("." + target).html(html);
    });
}$(document).ready(function() {
    $("#searchForm").on("submit", searchAll);
    $("#searchInput").on("keypress", function(e) {
        if (e.which == 13) {
            e.preventDefault();
            searchAll(e);
        }
    });
    let params = new URLSearchParams(window.location.search);
    let query = params.get("q");
    if (query) {
        $("#searchInput").val(query);
        search(query, "members", "searchMembers");
        search(query, "entities", "searchEntities");
    }
});

