$.fn.badge = function(options) {
		var defaults = {
			type: 'default', // default, primary, success, info, warning, danger
			count: 0,
			text: '',
			inline: false,
			overlay: false,
			hideZero: false,
			html: false,
			update: null,
			updateInterval: 1000,
			alwaysShow: false,
			alwaysShowTimeout: 0,
			placement: 'top-right',
			onShow: null,
			onHide: null,
			onUpdate: null,
			selector: null,
			title: null
		};
		var opts = $.extend(defaults, options);

		var method = opts.method;
		delete opts.method;

		var $this = this;
		var $badge;
		var timeout;
		var timer;

		if (method == 'update') {
			if (timer) {
				clearInterval(timer);
			}
			timer = setInterval(function() {
				$this.badge('update', opts);
			}, opts.updateInterval);
			return;
		}

		if (method == 'destroy') {
			$badge.remove();
			$badge = null;
			return;
		}

		// create badge
		if ($this.length > 1) {
			$badge = $('<span class="badge"></span>').appendTo(this);
			$badge = $badge.filter(':last');
		} else if ($this.length == 1) {
			$badge = $this.data('badge');
			if (!$badge) {
				$badge = $('<span class="badge"></span>').appendTo($this);
			}
		}

		$badge
			.data('opts', opts)
			.addClass('badge-' + opts.type)
			.toggleClass('badge-inline', opts.inline)
			.toggleClass('badge-overlay', opts.overlay);

		if (opts.html) {
			$badge.html(opts.count);
		} else if (opts.count > 0 || opts.text.length > 0) {
			$badge.text(opts.count);

			if (opts.text.length > 0) {
				$badge.append('<span class="badge-text">' + opts.text + '</span>');
			}
		} else if (opts.hideZero) {
			$badge.hide();
		}

		// show badge
		if (opts.alwaysShow) {
			$badge.show();
			if (opts.alwaysShowTimeout) {
				clearTimeout(timeout);
				timeout = setTimeout(function() {
					$this.badge('hide');
				}, opts.alwaysShowTimeout);
			}
		} else {
			$badge.appear();
		}

		// update badge
		if (typeof opts.update == 'function') {
			timer = setInterval(function() {
				$this.badge('update', opts);
			}, opts.updateInterval);
		}

		$this.data('badge', $badge);
	};

