function displayMessage(newMessage) {
    var message = newMessage.message,
        user = message.user,
        html = '',
        mention = chat.getQuery() && message.text && message.text.toLowerCase().indexOf("<" + chat.getQuery().toLowerCase() + ">") === 0,
        timestamp = (new Date(message.timestamp * 1000)).toLocaleTimeString();

    if (user.mentionName && mention) {
        html += '<strong class="bot-mention">@' + user.mentionName + '</strong>';
    }

    html += message.text;

    if (message.media && message.media.url) {
        html = '<a href="' + message.media.url + '">' + html + '</a>';
    }

    if (message.sticker && message.sticker.url) {
        html = '<img src="' + message.sticker.url + '">' + html;
    }

    if (message.location && message.location.lat && message.location.lng) {
        html = '<a href="https://www.openstreetmap.org/#map=18/' + message.location.lat + '/' + message.location.lng + '">' + html + '</a>';
    }

    chat.addMessage({
        user: user.name,
        html: html,
        timestamp: timestamp,
        mention: mention
    });

    chat.scrollToBottom();
}ss

