Alert.$inject = ['$modal', 'toastr'];
function Alert($modal, toastr) {
  return {
    /**
     * Opens a modal with a custom alert template and controller.
     * @param {Object} options - Options to pass to the modal controller.
     * @returns {Promise} - Resolved when the modal is closed.
     */
    open: function open(options) {
      options = options || {};
      var template = options.template || 'common/alert.html';
      var controller = options.controller || 'AlertController';
      var resolve = options.resolve || {};
      var locals = { alert: options.alert || {} };
      return $modal.open({
        template: '<script type="text/ng-template" id="common/alert.html">' +
                    '<alert></alert>' +
                  '</script>',
        controller: ['$scope', '$modalInstance', controller],
        resolve: resolve,
        locals: locals
      }).result;
    },
    /**
     * Shows a simple toastr notification.
     * @param {String} type - The type of notification to show (success, warning, error, info).
     * @param {String} title - The title of the notification.
     * @param {String} message - The message of the notification.
     */
    show: function show(type, title, message) {
      toastr[type](message, title);
    }
  };
}

