function addRowInteractions() {
  $('tr[data-toggle="row"]').on('click', function(event) {
    var $row = $(this).closest('tr');

    if ($row.data('details')) {
      $row.collapse('toggle');
      $row.toggleClass('active');
      event.preventDefault();
    }
  });

  $('tr[data-toggle="row"] .details-control').on('click', function(event) {
    var $control = $(this);
    var $row = $control.closest('tr');
    var id = $row.data('toggle');
    var $detailRow = $('#' + id);

    if ($row.hasClass('active')) {
      $row.collapse('hide');
      $row.removeClass('active');
    } else {
      $row.collapse('show');
      $row.addClass('active');

      // If the details row doesn't eist in the DOM yet, look for it in the template
      if ($detailRow.length === 0) {
        var $templateRow = $row.clone();
        var idMatch = $templateRow.data('toggle').match(/^(.+)-(.+)$/);

        if (idMatch) {
          $templateRow.attr('id', idMatch[2]);
          $templateRow.data('toggle', idMatch[2]);
          $templateRow.find('.details-control').html($control.html());
        }

        $templateRow.find('td').attr('class', function() {
          return '';
        });

        $detailRow = $templateRow.wrap('<div/>').parent().html();
      }

      $row.append($detailRow);
    }

    event.preventDefault();
  });

  // Select rows with checkboxes
  $('tr[data-toggle="check"]').on('click', function(event) {
    var $row = $(this).closest('tr');
    var $input = $row.find('input[type="checkbox"]');
    var checked = $input.prop('checked');

    if ($input.length) {
      $input.prop('checked', !checked);
      $row.toggleClass('active', !checked);
    }

    event.preventDefault();
  });
}addRowInteractions();

