(function( $ ) {

$.fn.dynatree = function( options, arg2, arg3 ) {
	return this.each(function() {
		var tree,
			init = false,
			// If a selector was given, find all matching elements first
			$elems = this.nodeType ? $(this) : $(this).find(options.selector || "*"),
			len = $elems.length,
			i;

		for ( i = 0; i < len; i++ ) {
			tree = $.data( $elems[i], "dynatree" );
			if ( !tree ) {
				tree = new DynaTree( $elems[i], options, arg2, arg3 );
				$.data( $elems[i], "dynatree", tree );
				tree.init();
				init = true;
			// Reinit tree if options.ajax.url changed
			} else if ( init || options.ajax.url !== undefined && tree.options.ajax.url === undefined ) {
				tree.initOptions(options);
				if ( options.ajax.url !== undefined ) {
					tree.options.ajax.url = options.ajax.url;
				}
				tree.reinit();
				init = true;
			}
		}

		// Return collection for chaining
		return $elems;
	});
};

})(jQuery);

