function updateOptionValuesAndPreviewText() {
	var $this = $(this),
		$input = $this.find('input, textarea'),
		$preview = $this.find('.option-preview'),
		type = $input.attr('type');

	if (type === 'checkbox' || type === 'radio') {
		$preview.html($input.is(':checked') ? $input.val() : '');
	} else if (type === 'textarea') {
		$preview.html($input.val());
	} else {
		$preview.html($input.val() === '' ? $input.attr('placeholder') : $input.val());
	}
}

