func newTransport(tlsConfig *tls.Config) http.RoundTripper {
	// http.Transport doesn't like nil *tls.Config, so if passed nil use empty
	// config.
	if tlsConfig == nil {
		tlsConfig = &tls.Config{}
	}
	tr := &http.Transport{
		TLSClientConfig: tlsConfig,
		Proxy:           http.ProxyFromEnvironment,
	}
	// Increase the connection pool from the default of 2 idle per host to 10.
	// This allows us to make full use of the connection keep alive feature
	// when making requests in quick succession.
	tr.MaxIdleConnsPerHost = 10

	return tr
}

