const { promisify } = require('util');
const child_process = require('child_process');
const fs = require('fs');
const path = require('path');

const readFile = promisify(fs.readFile);
const writeFile = promisify(fs.writeFile);

const { BACKEND_URL } = process.env;

if (!BACKEND_URL) {
  throw new Error('BACKEND_URL environment variable must be set.');
}

async function main() {
  const filePath = path.resolve(__dirname, '../dist/assetmap.json');
  const fileBuffer = await readFile(filePath);

  const { stdout } = await child_process.spawn(
    'curl',
    [
      '--header',
      'Content-Type: application/json',
      '--data',
      `@-`,
      `${BACKEND_URL}/api/assetmap`,
    ],
    { input: fileBuffer, stdio: ['pipe', 'inherit', 'inherit'] }
  );

  const json = JSON.parse(stdout);
  const newAssetmapPath = path.resolve(__dirname, '../dist', json.path);
  await writeFile(newAssetmapPath, json.content);
  console.log(`Updated assetmap to ${newAssetmapPath}`);
} main().catch(err => {
  console.error(err);
  process.exit(1);
});

