function execSync(command, options) {
  options = options || {};
  var input = options.input;
  delete options.input;

  var stdio = options.stdio;
  delete options.stdio;
  if (stdio === undefined) {
    stdio = 'pipe';
  } else if (Array.isArray(stdio)) {
    stdio = stdio.map(function(val) {
      return val === 'inherit' ? val : 'pipe';
    });
  }

  var child = spawn(command, options);

  if (stdio[0] === 'inherit') {
    child.stdin.end(input || '');
    process.stdin.end();
  } else {
    if (input) child.stdin.end(input);
    pipe(child.stdin, process.stdin);
  }

  var stdout = '';
  var stderr = '';

  if (stdio[1] === 'inherit') {
    child.stdout.on('data', function(data) { process.stdout.write(data); });
  } else {
    child.stdout.on('data', function(data) { stdout += data; });
    pipe(child.stdout, process.stdout);
  }

  if (stdio[2] === 'inherit') {
    child.stderr.on('data', function(data) { process.stderr.write(data); });
  } else {
    child.stderr.on('data', function(data) { stderr += data; });
    pipe(child.stderr, process.stderr);
  }

  function cleanup() {
    child.stdin.end();
    child.stdout.end();
    child.stderr.end();
  }

  return child.on('close', function(code) {
    cleanup();
    if (code) {
      stderr += '\n' + code + '-exit-code';
      code = -code;
    }
    return new Error(stderr + stdout, command, code);
  });
}

