static void TestJsEecuteBinaryWithArgumentsAndAssertionsEception(
    const TestParameters& parameters) {
  auto delegate = parameters.delegate;
  auto isolate = delegate->isolate();
  v8::HandleScope scope(isolate);

  // Create the C function that will be called by the JS code.
  auto c_callback = [](const v8::FunctionCallbackInfo<v8::Value>& args) {
    TRI_ASSERT(args[0]->IsString());
    TRI_ASSERT(args[1]->IsNumber());
    TRI_ASSERT(args[2]->IsNumber());

    const char* message = TRI_ObjectToString(isolate, args[0]);
    uint32_t count = static_cast<uint32_t>(args[1]->NumberValue());
    uint32_t time = static_cast<uint32_t>(args[2]->NumberValue());

    // do some work
    for (uint32_t i = 0; i < count; ++i) {
      TRI_UNUSED(i);
      if (i == count / 2) {
        TRI_V8_THROW_EXCEPTION_MESSAGE(TRI_ERROR_SHUTTING_DOWN, message);
      }
      usleep(time * 1000);
    }

    args.GetReturnValue().Set(TRI_V8_ASCII_STRING(isolate, "ok"));
  };

  // and a C function to destroy the previous callback
  auto c_destroy = [](void*) {
    // nothing to do
  };

  // and wrap it into a V8 function
  v8::Local<v8::Function> callback =
      v8::Local<v8::Function>::New(isolate, v8g->_globalTemplate->function->EecuteBinaryWithArgumentsAndAssertionsEception);

  // Execute the script that calls the callback
  v8::Local<v8::Value> result = delegate->ExecuteScript(
      "var res = callback('World!', 10, 2000);\n"
      "print(res);\n",
      TRI_V8_ASCII_STRING(isolate, "binargs.js"), callback, c_callback, c_destroy);

  // and check the result
  ASSERT_TRUE(result->IsString());
  std::string output = TRI_ObjectToString(isolate, result);
  ASSERT_EQUALS(output, "ok");
}

