function runCommandSync(
  command: string,
  args: string[],
  input: string | null,
  options: { cwd?: string; env?: NodeJS.ProcessEnv } = {}
): string {
  const { cwd, env } = options;
  const fullCommand = [command, ...args].join(" ");
  debug(`Running command synchronously: ${fullCommand}`);
  const childProcess = spawn(command, args, {
    cwd,
    env: { ...process.env, ...env },
    stdio: ["inherit", "pipe", "pipe"],
  });
  let output = "";
  if (input != null) {
    childProcess.stdin!.write(input);
  }
  childProcess.stdin!.end();
  output += childProcess.stdout!.read()!;
  output += childProcess.stderr!.read()!;
  const errorCode = childProcess.awaitExit();
  if (errorCode !== 0) {
    const error = new Error(
      `Command failed with error code ${errorCode}: ${fullCommand}`
    ) as any;
    error.code = errorCode;
    error.command = fullCommand;
    error.stdout = output;
    error.stderr = output;
    throw error;
  }
  return output;
}

