function processImagesToTiles(images, options) {
  options = defaults(options, {
    imageType: 'image/png',
    width: 256,
    height: 256,
    overlap: 0,
    bounds: null,
    tileCache: null,
    createBounds: createTileBounds,
    loadTiles: true
  });

  var tiles = {};
  var bounds = options.bounds || globe.boundingBox();

  // for each image
  for (var id in images) {
    if (!images.hasOwnProperty(id)) continue;
    var image = images[id];

    // if the image does not cover the whole globe, skip it
    if (!bounds.containsRect(image.bounds)) continue;

    // create a tile for each tile bounding box
    var tileBoundsList = createTileBoundsList(bounds, image.bounds, options);
    for (var i = 0; i < tileBoundsList.length; i++) {
      var tileBounds = tileBoundsList[i];
      var key = tileBounds.key();

      // if tile caching is enabled and this tile is already in the cache, use it
      var tile = null;
      if (options.tileCache) {
        tile = options.tileCache.get(key);
        if (tile) {
          debug('Tile %o from cache', key);
        }
      }

      // if tile caching is disabled or the tile is not in the cache, create a new tile
      if (!tile) {
        tile = new Tile(options.width, options.height, options.overlap);
        tile.bounds = tileBounds;
        tile.image = image;
        tile.type = options.imageType;
      }

      // add the tile to the tile set
      if (!tiles[key]) tiles[key] = tile;
      else {
        warn('Duplicate tile: %o', key);
      }
    }
  }

  // for each tile
  for (var key in tiles) {
    if (!tiles.hasOwnProperty(key)) continue;
    var tile = tiles[key];

    // load the tile's image data
    if (options.loadTiles) {
      tile.setImageData();
    // if tile caching is enabled, put the tile in the cache
    } else if (options.tileCache) {
      options.tileCache.set(tile);
      debug('Tile %o put in cache', key);
    }
  }

  return tiles;
}

