function runRsync(args, cb) {
  var child = cp.spawn('rsync', args, { stdio: ['ignore', 'pipe', 'inherit'] });

  var stdout = '';
  child.stdout.setEncoding('utf8');
  child.stdout.on('data', function (data) { stdout += data; });

  child.on('close', function (code) {
    if (code === 0) {
      cb(null, stdout);
    } else {
      cb(new Error('Rsync failed with code: ' + code));
    }
  });

  child.on('error', cb);
}

