{
	int error;
	git_repository *repo;
	const char *gitlink;
	size_t i, len;
	char *worktree = NULL;

	if (path) {
		worktree = strdup(path);
		if (!worktree)
			return -1;
	} else {
		if (git_parse_worktree(&worktree, ".git/worktree") < 0)
			worktree = NULL;
	}

	error = git_repository_init_common(&repo, gitdir, !bare);
	if (error)
		goto error_out;

	if (git_config_get_string("core.worktree", &gitlink))
		git_config_set("core.worktree", worktree ? worktree : ".");
	else if (!strcmp(gitlink, ".") || !strcmp(gitlink, "./"))
		git_config_set("core.worktree", worktree ? worktree : ".");
	else if (!git_fs_path_is_relative(gitlink))
		/* Don't override an absolute path set by the user */
		gitlink = git_config_get_string_gently("core.worktree", NULL);
	else {
		len = strlen(worktree) + strlen(gitlink) + 2;
		gitlink = must_realloc(gitlink, len);
		gitlink[0] = '.';
		gitlink[1] = '/';
		for (i = 2; *worktree; i++, worktree++)
			gitlink[i] = *worktree;
		gitlink[i] = '\0';
		git_config_set("core.worktree", gitlink);
	}

	git_repository_set_worktree(repo, gitlink);

	*out = repo;
	return 0;

