	git_strbuf_addf(&sb, "%s/objects", path);
	error = git_mkdir_or_exist(sb.buf);
	if (error)
		goto error_out;

	git_strbuf_addf(&sb, "%s/refs", path);
	error = git_mkdir_or_exist(sb.buf);
	if (error)
		goto error_out;

	git_strbuf_addf(&sb, "%s/refs/heads", path);
	error = git_mkdir_or_exist(sb.buf);
	if (error)
		goto error_out;

