		gitdir = gitdir_path;
		worktree = worktree_path;

		git_strbuf_addf(&submodule->gitdir_sb, "%s/.git", gitdir_path);
		git_strbuf_addf(&submodule->worktree_sb, "%s", worktree_path);

		submodule->gitdir = submodule->gitdir_sb.buf;
		submodule->worktree = submodule->worktree_sb.buf;

		error = git_repository_init_common(&subrepo, submodule->gitdir, 1);
		if (error)
