        onClick={() => shareContent(content, 'twitter')}
        target="_blank"
        rel="noopener noreferrer"
      >
        <img
          src="/images/social-media/twitter-color.png"
          alt={t`Share on Twitter`}
        />
      </a>

      <a
        className="ShareContent__social-media-link"
        href={shareEmail(content)}
        onClick={() => shareContent(content, 'email')}
        target="_blank"
        rel="noopener noreferrer"
      >
        <img
          src="/images/social-media/envelope-color.png"
          alt={t`Share via Email`}
        />
      </a>
