    <h3>{t`How can we help you?`}</h3>

    <p>{t`If you have any questions or need further assistance, please don't hesitate to contact us.`}</p>

    <p>
      <Button type="button" onClick={() => dispatch(push('/contact'))}>
        {t`Contact us`}
      </Button>
    </p>
  </div>
);

