import { markPageNotificationsRead } from 'containers/Notifications/actions';

import { makeSelectUser } from './selectors';
import { loadUser } from './actions';

import './style.scss';

export class UserProfilePage extends React.PureComponent { // eslint-disable-line react/prefer-stateless-function
  static propTypes = {
    match: PropTypes.object,
    loadPage: PropTypes.func,
    loadMorePageContributors: PropTypes.func,
    page: PropTypes.object,
    pageContributors: PropTypes.object,
    pageEntityLinks: PropTypes.object,
