    pageLoaded: PropTypes.bool,
    pageLoading: PropTypes.bool,
    pageTags: PropTypes.object,
    contributions: PropTypes.object,
    currentUser: PropTypes.object,
    isAuthenticated: PropTypes.bool,
    loadUser: PropTypes.func,
    user: PropTypes.object,
    notifications: PropTypes.object,
    markPageNotificationsRead: PropTypes.func,
  };

  componentDidMount() {
    const { loadPage, match, loadUser, currentUser, isAuthenticated } = this.props;
    const username = match.params.username;

    loadPage(username);
    loadUser(username);

    if (isAuthenticated && currentUser.getIn(['sub']) !== username) {
      this.props.markPageNotificationsRead(username);
    }
  }

  componentDidUpdate(prevProps) {
    const { page, loadMorePageContributors, pageContributors, pageHasMoreContributors } = this.props;

    if (!pageContributors.isEmpty() && pageHasMoreContributors && pageContributors.size < page.get('contributor_count')) {
      loadMorePageContributors(page.get('username'));
    }
  }

  render() {
    const {
      page,
      pageContributors,
      pageEntityLinks,
      pageTags,
      contributions,
      currentUser,
      isAuthenticated,
      notifications,
    } = this.props;

    const username = page.get('username');
    const user = this.props.user.get('user');

    if (page.get('is_error')) {
      return <div className="user-profile-page error">Page not found</div>;
    }

    if (!page.get('is_loaded')) {
      return <LoadingIndicator />;
    }

    const isCurrentUser = isAuthenticated && currentUser.getIn(['sub']) === username;
    const isFollowing = user && user.get('followers').includes(currentUser.get('sub'));
    const canEdit = isCurrentUser || (user && user.get('is_admin'));

    let pageContent;
    if (page.get('content')) {
      pageContent = (
        <div className="user-profile-page__content" dangerouslySetInnerHTML={{ __html: page.get('content') }} />
      );
    } else if (page.get('is_deleted')) {
      pageContent = <PageNoContent text="This page has been deleted." />;
    } else {
      pageContent = <PageEmptyContent text="This page has no content." />;
    }

    const pageActions = (
      <PageActions
        canEdit={canEdit}
        isFollowing={isFollowing}
        page={page}
        currentUser={currentUser}
        notifications={notifications}
      />
    );

    const pageHeader = (
      <PageHeader
        title={page.get('title')}
        author={page.get('author')}
        date={moment(page.get('created_at')).format('MMMM D, YYYY')}
        actions={pageActions}
      />
    );

    const pageBreadcrumbs = (
      <PageBreadcrumbs
        username={page.get('username')}
        title={page.get('title')}
        author={page.get('author')}
      />
    );

    const pageEntityLinkItems = pageEntityLinks.map(link => (
      <PageEntityLinks.Item
        key={link.get('id')}
        link={link}
        username={page.get('username')}
      />
    ));

    const pageTagsItems = pageTags.map(tag => (
      <PageTags.Item
        key={tag.get('id')}
        tag={tag}
        username={page.get('username')}
      />
    ));

    const pageContributorsList = (
      <PageContributors
        loading={page.get('is_loading_contributors')}
        loaded={page.get('is_loaded_contributors')}
        hasMore={page.get('has_more_contributors')}
        onLoadMore={() => this.props.loadMorePageContributors(page.get('username'))}
        contributors={pageContributors}
      />
    );

    const pageComments = (
      <PageComments
        username={page.get('username')}
        title={page.get('title')}
        author={page.get('author')}
        content={page.get('content')}
      />
    );

    const userContributionsList = (
      <PageContributors
        loading={false}
        loaded={true}
        hasMore={false}
        contributors={contributions}
        username={user.get('username')}
      />
    );

    return (
      <div className="user-profile-page">
        <Helmet>
          <title>{page.get('title') ? `${page.get('title')} by ${username} |` : ''} Hacker News</title>
        </Helmet>

        {pageBreadcrumbs}
        {pageHeader}
        <div className="user-profile-page__inner">
          <div className="user-profile-page__main">
            {pageContent}
            {pageEntityLinkItems.length > 0 && <div className="user-profile-page__links"><h3>Links</h3>{pageEntityLinkItems}</div>}
            {pageTagsItems.length > 0 && <div className="user-profile-page__tags"><h3>Tags</h3>{pageTagsItems}</div>}
            {pageContributorsList}
            {pageComments}
          </div>
          <aside className="user-profile-page__sidebar">
            <div className="user-profile-page__user">
              <img className="user-profile-page__avatar" src={user.get('avatar_url')} alt={user.get('username')} />
              <div>
                <h2>{user.get('username')}</h2>
                <p>{user.get('karma')} karma</p>
              </div>
            </div>
            <h3>Contributions</h3>
            {user.get('username') === currentUser.get('sub') ? userContributionsList : pageContributorsList}
          </aside>
        </div>
      </div>
    );
  }
}

const mapStateToProps = createStructuredSelector({
  currentUser: makeSelectCurrentUser(),
  page: makeSelectPage(),
  pageContributors: makeSelectPageContributors(),
  pageEntityLinks: makeSelectPageEntityLinks(),
  pageHasMoreContributors: makeSelectPageHasMoreContributors(),
  pageLoaded: makeSelectPageLoaded(),
  pageLoading: makeSelectPageLoading(),
  pageTags: makeSelectPageTags(),
  contributions: makeSelectUserContributions(),
  user: makeSelectUser(),
  isAuthenticated: makeSelectIsAuthenticated(),
  notifications: makeSelectNotifications(),
});

const mapDispatchToProps = {
  loadPage,
  loadMorePageContributors,
  loadUser,
  markPageNotificationsRead,
};

const withConnect = connect(mapStateToProps, mapDispatchToProps);

export default compose(
  withConnect,
)(UserProfilePage);

