func getDailyTallies(w http.ResponseWriter, r *http.Request) {
	tallyLimit := 30

	ct := getPostCountTallyLimit(r)

	// Use a query parameter to override the default tally limit
	if tallyLimitStr := r.URL.Query().Get("limit"); tallyLimitStr != "" {
		t, err := strconv.Atoi(tallyLimitStr)
		if err != nil || t == 0 {
			tallyLimit = 30
		} else {
			tallyLimit = t
		}
	}

	// Do not show negative tallies in the API
	where := `WHERE views > 0`

	// If we're doing a post count tally, add a Posts column to the select
	// and add a condition to only include users with published posts
	if ct {
		where = `WHERE views > 0 AND published > 0`
	}

	// Set up the query to get the daily tallies
	query := fmt.Sprintf(`
SELECT DATE(created_at) AS day, SUM(views) AS views, %s
FROM posts
%s
GROUP BY day
ORDER BY day DESC LIMIT %d`, returnColumns(ct), where, tallyLimit)

	rows, err := db.Query(query)
	if err != nil {
		http.Error(w, "Database error", http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	tallies := make([]map[string]interface{}, 0)
	for rows.Next() {
		tally := make(map[string]interface{})
		if err := rows.Scan(&tally["day"], &tally["views"]); err != nil {
			http.Error(w, "Database error", http.StatusInternalServerError)
			return
		}
		if ct {
			tally["posts"] = 0
		}
		tallies = append(tallies, tally)
	}

	if err := rows.Err(); err != nil {
		http.Error(w, "Database error", http.StatusInternalServerError)
		return
	}

	writeJSON(w, tallies)
}

