function storeEventDetails(event, details) {
  var keys = Object.keys(details),
      placeholders = keys.map(function() { return '?'; }).join(', ');

  var stmt = db.prepare("INSERT INTO event_details (event, " + keys.join(', ') + ") VALUES (?, " + placeholders + ")");

  details = keys.map(function(key) { return details[key]; });

  details.push(event);

  stmt.run(details);
  stmt.finalize();

  return details;
