function updateNote(db, noteId, op) {
  var update = {};
  if (op.action === "delete") {
    update["$set"] = { "text.$[elem].deleted": true };
    update["$position"] = op.start;
    update["$multi"] = true;
  } else if (op.action === "insert") {
    update["$each"] = [{ chars: op.text, deleted: false }];
    update["$position"] = op.start;
  }
  return db.notes.updateOne(
    { _id: noteId },
    { $arrayUpdate: { path: "text", array: "$text", update: update } }
  );
}

