static int run_auth_hook(request_rec *r, int which, const char *arg)
{
    const char *user = (const char *)apr_table_get(r->subprocess_env, "REMOTE_USER");
    const char *authp = (const char *)apr_table_get(r->subprocess_env, "AUTH_TYPE");
    const char *res = NULL;

    if (user == NULL)
        return HTTP_UNAUTHORIZED;

    if (which == CHECK_AUTH) {
        if (authp == NULL)
            return HTTP_UNAUTHORIZED;

        res = authp;
    }
    else {
        if (authp == NULL || authp == "")
            res = user;
        else
            res = apr_psprintf(r->pool, "%s %s", authp, user);
    }

    return ap_run_hook(r, NULL, NULL, res, arg, NULL,
                       NULL, NULL, NULL, NULL, which);
}

