static char *_unique_short(struct mg_connection *conn, const char *in,
                           const struct mg_str *args) {
  char shortname[256], longname[256], aname[256], bname[256];
  const char *name = in;
  int off = 0;
  struct mg_str str;
  while(*in && off < sizeof(shortname)-1) {
    if(*in == ' ') {
      off--;
      break;
    }
    if(*in == ',' || *in == '\n') break;
    if(*in == '.') {
      if(in[1] == ',' || in[1] == '\n') break;
      if(off+1 < sizeof(shortname)-1 && isdigit(in[1])) {
        in++;
        break;
      }
    }
    shortname[off++] = *in++;
  }
  shortname[off] = '\0';
  if(shortname[0] == '\0') return(NULL);

  str.ptr = longname;
  str.len = sizeof(longname);

  if(args && args->len > 0) {
    if(mg_strchr(args, 'A') != NULL) {
      name = _get_arg_value(args, "A", aname, sizeof(aname));
      if(name == NULL) name = aname;
    }
    if(args->len > 1 && mg_strchr(args, 'B') != NULL) {
      name = _get_arg_value(args, "B", bname, sizeof(bname));
      if(name == NULL) name = bname;
    }
  }

  for(int i = 0; i < 10; i++) {
    _sql_get_longname(conn, name, i, longname, sizeof(longname));
    if(str.len >= sizeof(longname) || longname[0] == '\0') break;
  }

  return(mg_strn2cstr(conn, longname, shortname, sizeof(shortname)));
}  // _unique_short

