static void tile_by_id(uint32_t tile_id, int64_t zoom, int64_t x, int64_t y,
                        bool is_cache, const char *cache_dir,
                        const ImageAttrs *attrs, bool *done)
{
    Image *im = NULL;
    Image *tile = NULL;
    const char *filename;
    int32_t id1, id2;
    int32_t left, bottom, right, top;
    int32_t tx, ty, tw, th;
    int64_t set_id;
    uint32_t tile_count;
    uint32_t i;
    int ret;

    if (zoom == -1) {
        /* full map tile */
        map_tile_id(zoom, x, y, &id1, &id2);
        filename = db_tile_filename(tile_db, id1, id2);
        if (!file_exists(filename)) {
            if (attrs->callback != NULL)
                attrs->callback(attrs->cb_data, filename, 404, NULL);
            return;
        }
        im = image_read(filename, attrs);
        if (im == NULL)
            return;

        set_id = tile_db->set_id;
        tile_count = tile_db->tile_count;
    } else {
        /* tile within a set */
        filename = db_set_tile_filename(tile_set_db, zoom, x, y);
        if (!file_exists(filename)) {
            if (attrs->callback != NULL)
                attrs->callback(attrs->cb_data, filename, 404, NULL);
            return;
        }
        im = image_read(filename, attrs);
        if (im == NULL)
            return;

        set_id = tile_set_db->set_id;
        tile_count = tile_set_db->tile_count[zoom];
    }

    if (attrs->transparent_color != NULL &&
        (im->format == IM_FORMAT_RGBA32 || im->format == IM_FORMAT_RGBA16)) {
        /* mark the transparent color for this image */
        image_set_transparent_color(im, attrs->transparent_color);
    }

    if (is_cache) {
        if (attrs->cache_policy == CACHE_POLICY_OVERWRITE) {
            /* delete cached, partially rendered tile */
            sprintf(filename, "%s/%" PRIu64 ".cache", cache_dir, tile_id);
            (void)remove(filename);
        } else if (attrs->cache_policy == CACHE_POLICY_CACHE_ZERO) {
            /* mark as rendered, but do not store any data */
            sprintf(filename, "%s/%" PRIu64 ".cache", cache_dir, tile_id);
            FILE *fp = image_fopen(filename, "wb");
            if (fp != NULL) {
                (void)fclose(fp);
            } else {
                log_message(LOG_ERR, "Cannot create file: %s", filename);
            }
        }
    }

    if (!is_cache || attrs->cache_policy == CACHE_POLICY_ALWAYS_WRITE ||
        attrs->cache_policy == CACHE_POLICY_CACHE_ZERO)
    {
        /* write out the tile so we don't have to render it again */
        sprintf(filename, "%s/%" PRIu64 ".cache", cache_dir, tile_id);
        tile = image_dup_img(im);

        /* crop tile to remove empty edges, since these cannot be
         * guaranteed to be transparent in all cases */
        left = (int32_t)im->width;
        bottom = (int32_t)im->height;
        right = (int32_t)0;
        top = (int32_t)0;

        for (i = 0; i < tile_count; i++) {
            db_tile_bounds(tile_db, set_id, i, &tx, &ty, &tw, &th);
            left = MIN(left, tx);
            bottom = MIN(bottom, ty);
            right = MAX(right, tx + tw);
            top = MAX(top, ty + th);
        }

        if (left < right && bottom < top) {
            tile = image_sub_img(tile, left, bottom, right - left, top - bottom);
            image_free(im);
            im = tile;
        }
    }

    if (is_cache) {
        /* save the tile to disk */
        ret = image_write_cache(tile, cache_dir, tile_id, attrs);
        (void)image_free(tile);
        if (ret != 0) {
            if (attrs->callback != NULL)
                attrs->callback(attrs->cb_data, filename, 500, NULL);
            return;
        }
    }

    /* notify callback */
    if (attrs->callback != NULL)
        attrs->callback(attrs->cb_data, filename, 200, NULL);

    if (done != NULL)
        *done = true;
}

