def search_taxon_names(params = {})
    q = params[:q] || "*"
    page = params[:page] || 1
    per_page = params[:per_page] || 20
    order = params[:order] || "sciname"
    direction = params[:direction] || "asc"
    filters = params[:filters] || {}

    search_taxa(q, page, per_page, order, direction, filters)
  end

  def search_taxa(q, page, per_page, order, direction, filters)
    result = TaxonName.search(
      {
        query: {
          bool: {
            must: [
              { multi_match: { query: q, fields: [ "sciname^2", "authorship^2", "name_class", "taxon_name_relationship_type", "preferred_flag" ] } }
            ],
            filter: [
              { term: { status: "accepted" } },
              { term: { rank: "species" } },
              { term: { "taxon_name_relationship_type.preferred_flag": true } }
            ] + (filters[:name_class] ? [{ term: { name_class: filters[:name_class] } }] : [])
          }
        },
        sort: [
          { order: "#{direction}" },
          { sciname: "#{direction}" }
        ],
        from: (page - 1) * per_page,
        size: per_page
      }
    )

    {
      results: result.map { |taxon_name| TaxonNamePresenter.new(taxon_name) },
      total: result.total
    }
  end

def search_restaurants(params)
