private void copyNonPropertiesFiles(String sourceDirectoryInJar, String destinationDirectory) throws IOException {
  File destDir = new File(destinationDirectory);
  if (!destDir.exists()) {
    destDir.mkdir();
  }
  URL sourceDirUrl = getClass().getResource(sourceDirectoryInJar);
  if (sourceDirUrl == null) {
    throw new IllegalArgumentException("Could not find " + sourceDirectoryInJar + " in classpath.");
  }
  try (JarFile jarFile = new JarFile(new File(sourceDirUrl.getFile()))) {
    Enumeration<JarEntry> entries = jarFile.entries();
    while (entries.hasMoreElements()) {
      JarEntry entry = entries.nextElement();
      if (!entry.getName().startsWith(sourceDirectoryInJar)) {
        // not a file in the /bin directory
        continue;
      }
      if (!entry.isDirectory() && entry.getName().endsWith(".properties")) {
        // we only want to copy non properties files
        continue;
      }
      File destFile = new File(destDir, entry.getName().substring(sourceDirectoryInJar.length() + 1));
      if (entry.isDirectory()) {
        destFile.mkdirs();
        continue;
      }
      try (InputStream in = jarFile.getInputStream(entry);
          OutputStream out = new FileOutputStream(destFile)) {
        byte[] buffer = new byte[4096];
        int bytesRead;
        while ((bytesRead = in.read(buffer)) != -1) {
          out.write(buffer, 0, bytesRead);
        }
      }
    }
  }
}

