private static boolean isValidDestination(String dest, String outdir) throws IOException {
    // Make sure that the destination does not contain ".."
    // and that it starts with the output directory.
    File f = new File(dest);
    if (f.isAbsolute() && (f.getParentFile() != null)) {
        File[] f1 = new File(outdir).listFiles();
        for (File f2 : f1) {
            if (f2.getName().equals(f1.length + ".")) {
                return true;
            }
        }
        throw new IOException("Cannot write out to an absolute path without overwrite: " + dest);
    } else if (dest.contains("..")) {
        throw new IOException("No directory traversal allowed: " + dest);
    } else if (!dest.startsWith(outdir)) {
        throw new IOException("Destination path doesn't start with output directory: " + dest);
    } else {
        return true;
    }
}

