def _parse_jeos_image_config(self, source, config):
        for line in source:
            line = line.strip()
            if not line or line.startswith("#"):
                continue

            try:
                key, value = line.split("=", 1)
            except ValueError:
                self._log.error("Invalid line in jeos image config file: %s", line)
                continue

            key = key.strip()
            value = value.strip()

            if key in config:
                self._log.warning("Duplicate entry in jeos image config file: %s", key)
                continue

            config[key] = value

