@app.route("/jobs/<jobdir>/<path:subpath>", methods=["GET"])
@login_required
def browse_job(jobdir, subpath):
    job = db.job_by_name(jobdir)
    if not job:
        abort(404)
    if not current_user.can_access_job(job):
        abort(403)

    # Redirect /jobs/<jobdir>/ to /jobs/<jobdir>/index.html
    if not subpath:
        return redirect(url_for("browse_job", jobdir=jobdir, subpath="index.html"))

    # Check that no parent of subpath is ".." or contains "/../"
    parts = subpath.split("/")
    for part in parts:
        if part == ".." or (part.startswith("..") and not part.startswith("...")):
            abort(400)

    # Render the file
    path = os.path.join(job.workdir, subpath)
    if os.path.isdir(path):
        # Directory
        return render_template("jobdir.html", job=job, path=subpath)
    else:
        # File
        return render_template("jobfile.html", job=job, path=subpath, file_contents=readfile(path))

