def _replace_dir(self, dest_dir, src_dir):
    for root, dirs, files in os.walk(src_dir):
        relative_root = os.path.relpath(root, src_dir)
        dest_root = os.path.join(dest_dir, relative_root)

        # Create directory
        if not os.path.isdir(dest_root):
            os.makedirs(dest_root)

        for f in files:
            src_file = os.path.join(root, f)
            dest_file = os.path.join(dest_root, f)

            # Copy file
            shutil.copy2(src_file, dest_file)

            # Adjust permissions for webserver
            if self.config['server'] in ['lighttpd', 'apache2']:
                os.chmod(dest_file, 0444) # -r--r--r--

