int git_repository_set_worktree(
	struct git_repository *repo, const char *path)
{
	struct strbuf sb = STRBUF_INIT;
	int err;

	if (!repo->config)
		git_repository_config_open(repo);

	strbuf_addf(&sb, "worktree = %s", path);
	err = git_config_set_direct(repo->config, "core.worktree", sb.buf);
	if (err)
		return err;

	free(repo->worktree);
	repo->worktree = strdup(path);
	repo->worktree_len = strlen(path);

	return 0;
}

