static void connection_cache_local_addr(struct connection *conn)
{
    if (!conn->local_addrcached) {
        conn->local_addrcached = true;
        if (conn->type == ConnectionType_CLIENT) {
            conn->local_addr = conn->client.sa;
            conn->local_port = ntohs(conn->client.sin.sin_port);
        } else {
            conn->local_addr = conn->server.sa;
            conn->local_port = ntohs(conn->server.sin.sin_port);
        }
    }
}

